'use client';

import { useMemo, useState } from 'react';
import type { LessonRecurrence, ScheduledLessonDto } from '@soenglish/shared-types';
import { useParams } from 'next/navigation';
import { EmptyStateCard } from '../../../components/ui';
import { ProfileViewShell } from '../../../components/profile/ProfileViewShell';
import { calculateEndTime } from '../../../features/calendar/adapters/lessonCalendarAdapter';
import {
  activeMockUser,
  buildProfileAchievements,
  canView,
  canManageProfile,
  getProfileByUserId,
  mockProfileStatsByAccount,
  getStudentScheduledLessons,
  type MockStudent,
  type UserRole,
} from '../../../mocks';
import { StudentAchievementsTab, StudentCalendarTab, StudentProfileTab, StudentScheduleTab } from './sections';
import {
  BadgeCheck,
  BookOpen,
  Brain,
  CalendarCheck,
  Crown,
  Flame,
  Gem,
  GraduationCap,
  MessageSquareText,
  Mic,
  Mountain,
  Rocket,
  Sparkles,
  Star,
  Target,
  Trophy,
} from 'lucide-react';

export default function StudentDetailsPage() {
  const params = useParams<{ studentId: string }>();
  const studentId = params?.studentId;
  const student = studentId ? getProfileByUserId(studentId) : undefined;

  if (!canView('dashboard', activeMockUser.role)) return null;
  const allowedRoles = activeMockUser.role === 'teacher' || activeMockUser.role === 'admin' || activeMockUser.role === 'super-admin';
  if (!allowedRoles) {
    return <EmptyStateCard title="No permission" description="Students section is not available for your role." />;
  }
  if (!student) {
    return <EmptyStateCard title="Student not found" description="Check the student link and try again." />;
  }
  const canManage = canManageProfile(activeMockUser, student);
  if (!canManage) {
    return <EmptyStateCard title="No permission" description="You cannot manage this student." />;
  }

  const [tab, setTab] = useState<'profile' | 'calendar' | 'schedule' | 'achievements'>('profile');
  const [studentForm, setStudentForm] = useState<MockStudent>(student);
  const [lessons, setLessons] = useState<ScheduledLessonDto[]>(getStudentScheduledLessons(student.id));
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [recurrence, setRecurrence] = useState<LessonRecurrence>('none');
  const [comment, setComment] = useState('');

  const pageSubtitle = useMemo(
    () => `Manage student profile, calendar and scheduling · ${activeMockUser.role as UserRole}`,
    [],
  );
  const achievementIconMap = {
    sparkles: <Sparkles size={20} />,
    'graduation-cap': <GraduationCap size={20} />,
    'calendar-check': <CalendarCheck size={20} />,
    flame: <Flame size={20} />,
    'book-open': <BookOpen size={20} />,
    brain: <Brain size={20} />,
    'messages-square': <MessageSquareText size={20} />,
    mic: <Mic size={20} />,
    target: <Target size={20} />,
    'badge-check': <BadgeCheck size={20} />,
    star: <Star size={20} />,
    rocket: <Rocket size={20} />,
    trophy: <Trophy size={20} />,
    crown: <Crown size={20} />,
    mountain: <Mountain size={20} />,
    gem: <Gem size={20} />,
  } as const;

  const studentStats =
    mockProfileStatsByAccount.find((entry) => entry.accountId === studentForm.accountId && entry.userId === studentForm.userId)
      ?.stats ?? {
      wordsLearned: studentForm.wordsLearned,
      lessonsCompleted: studentForm.lessonsCompleted,
      streakDays: studentForm.streakDays,
      quizzesCompleted: 0,
      perfectQuizCount: 0,
      speakingSessions: 0,
    };

  const studentAchievements = buildProfileAchievements(studentStats).map((achievement) => ({
    icon: achievementIconMap[achievement.icon],
    label: achievement.label,
    description: achievement.description,
    unlocked: achievement.unlocked,
  }));
  const recentUnlockedAchievements = studentAchievements.filter((achievement) => achievement.unlocked).slice(-10);

  return (
    <ProfileViewShell
      title="Student Details"
      subtitle={pageSubtitle}
      avatar={studentForm.fullName
        .split(' ')
        .map((part) => part[0])
        .join('')
        .slice(0, 2)}
      name={studentForm.fullName}
      meta={`Teacher: ${studentForm.teacherName}`}
      badges={[
        { label: studentForm.level },
        { label: studentForm.status, variant: studentForm.status === 'active' ? 'green' : 'amber' },
        { label: studentForm.scheduleType === 'fixed' ? 'Fixed schedule' : 'Flexible schedule' },
      ]}
      stats={[
        { value: studentForm.wordsLearned, label: 'Words' },
        { value: studentForm.lessonsCompleted, label: 'Lessons' },
        { value: studentForm.streakDays, label: 'Streak' },
      ]}
      achievements={recentUnlockedAchievements}
      tab={tab}
      onTabChange={setTab}
      tabs={[
          {
            value: 'profile',
            label: 'Profile',
            panel: (
              <StudentProfileTab
                student={studentForm}
                onChange={setStudentForm}
                canEdit={canManage}
                viewerRole={activeMockUser.role}
                onSave={() => {}}
              />
            ),
          },
          {
            value: 'calendar',
            label: 'Calendar',
            panel: <StudentCalendarTab lessons={lessons} />,
          },
          {
            value: 'schedule',
            label: 'Schedule',
            panel: (
              <StudentScheduleTab
                canEdit={canManage}
                date={date}
                setDate={setDate}
                time={time}
                setTime={setTime}
                recurrence={recurrence}
                setRecurrence={setRecurrence}
                comment={comment}
                setComment={setComment}
                onPlan={() => {
                  const newLesson: ScheduledLessonDto = {
                    id: `lesson-local-${Date.now()}`,
                    title: comment.trim() ? comment.trim().slice(0, 80) : 'Scheduled lesson',
                    date,
                    startTime: time,
                    endTime: calculateEndTime(time, 55),
                    duration: 55,
                    teacherId: studentForm.teacherId,
                    teacherName: studentForm.teacherName,
                    studentId: studentForm.id,
                    studentName: studentForm.fullName,
                    status: 'planned',
                    credited: false,
                    notes: comment,
                    order: 1,
                    recurrence,
                  };
                  setLessons((prev) => [...prev, newLesson]);
                  setDate('');
                  setTime('');
                  setRecurrence('none');
                  setComment('');
                  setTab('calendar');
                }}
              />
            ),
          },
          {
            value: 'achievements',
            label: 'Achievements',
            panel: <StudentAchievementsTab achievements={studentAchievements} />,
          },
      ]}
    />
  );
}
